SELECT COUNT(*)
FROM app_character_vote
WHERE character_id = #{characterId} AND vote = #{vote}

SELECT character_id
FROM app_character_favorite
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT f.character_id
FROM app_character_favorite f
LEFT JOIN (
    SELECT character_id, MAX(updated_at) AS last_at
    FROM app_conversation
    WHERE user_id = #{userId}
    GROUP BY character_id
) c ON c.character_id = f.character_id
WHERE f.user_id = #{userId}
ORDER BY COALESCE(c.last_at, f.created_at) DESC, f.created_at DESC
LIMIT #{limit}
